import React, { useState, useEffect, useCallback } from 'react';
import { UserProfile, AssessmentStage, LogEntry } from './types.ts';
import * as geminiService from './services/geminiService.ts';
import { audioService } from './services/audioService.ts';
import Card from './components/Card.tsx';
import Button from './components/Button.tsx';
import FoldingSquareLoader from './components/games/FoldingSquareLoader.tsx';
import { BrainCircuit, Dna, Menu, X, Home, ClipboardList, Volume2, Settings as SettingsIcon } from 'lucide-react';
import MiMap from './components/MiMap.tsx';
import CircuitBreakerDashboard from './components/MiTools.tsx';
import MiSound from './components/MiSound.tsx';
import TfmAuditConsole from './components/TfmAuditConsole.tsx';
import WelcomeScreen from './components/WelcomeScreen.tsx';
import AccessTierSelector from './components/AccessTierSelector.tsx';
import MTraAssessment from './components/MTraAssessment.tsx';
import MTraResultsScreen from './components/MTraResultsScreen.tsx';
import HBDIAssessment from './components/HBDIAssessment.tsx';
import HBDIResultsScreen from './components/HBDIResultsScreen.tsx';
import MBTIAssessment from './components/MBTIAssessment.tsx';
import MBTIResultsScreen from './components/MBTIResultsScreen.tsx';
import Logo from './components/Logo.tsx';
import SettingsDashboard from './components/SettingsDashboard.tsx';

const ProfileCompleteScreen: React.FC<{ userProfile: UserProfile, onEnter: () => void }> = ({ userProfile, onEnter }) => {
    if (!userProfile.baseArchetype) return null;
    return (
        <Card className="text-center max-w-lg mx-auto animate-fade-in">
            <Logo size={48} className="mx-auto mb-4" />
            <h1 className="text-3xl font-bold">Cognitive Profile Complete</h1>
            <p className="text-brand-text-muted mt-2">Welcome, {userProfile.baseArchetype.name}.</p>
            <p className="mt-4">Your personalized Cognitive Dashboard is now ready.</p>
            <Button onClick={onEnter} className="mt-8 text-lg py-3 px-8">
                Enter OS Dashboard
            </Button>
        </Card>
    );
};

const App: React.FC = () => {
    const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
    const [assessmentStage, setAssessmentStage] = useState<AssessmentStage>('welcome');
    const [assessmentData, setAssessmentData] = useState<any>({});
    const [isLoading, setIsLoading] = useState(true);
    const [isGeneratingProfile, setIsGeneratingProfile] = useState(false);
    const [activeTab, setActiveTab] = useState('mimap');
    const [isNavOpen, setIsNavOpen] = useState(false);
    const [colorMode, setColorMode] = useState('normal');

    useEffect(() => {
        const loadInitialData = async () => {
            try {
                await audioService.init();

                const savedProfileString = localStorage.getItem('userProfile');
                if (savedProfileString) {
                    const savedProfile: UserProfile = JSON.parse(savedProfileString);
                    if (savedProfile.baseArchetype && savedProfile.egotend && savedProfile.highertend) {
                        setUserProfile(savedProfile);
                        setAssessmentStage('complete');
                    }
                }
                const savedColorMode = localStorage.getItem('colorMode');
                if (savedColorMode) {
                    setColorMode(savedColorMode);
                }
            } catch (error) {
                console.error("Failed to load initial data:", error);
                localStorage.clear();
            } finally {
                setIsLoading(false);
            }
        };

        loadInitialData();
    }, []);

    const saveProfile = useCallback((profile: UserProfile) => {
        setUserProfile(profile);
        localStorage.setItem('userProfile', JSON.stringify(profile));
    }, []);

    const handleSetColorMode = (mode: string) => {
        setColorMode(mode);
        localStorage.setItem('colorMode', mode);
    }

    const handleGoHome = () => {
        setAssessmentStage('welcome');
        setActiveTab('mimap');
    };

    const handleWelcomeChoice = (choice: 'assessment' | 'dashboard') => {
        if (choice === 'assessment') {
            localStorage.removeItem('userProfile');
            localStorage.removeItem('mtraAnswers');
            localStorage.removeItem('hbdiAnswers');
            localStorage.removeItem('mbtiAnswers');
            setUserProfile(null);
            setAssessmentData({});
            setAssessmentStage('tier');
        } else if (choice === 'dashboard' && userProfile?.baseArchetype) {
            setAssessmentStage('complete');
        }
    };

    const handleSelectTier = (tier: 'basic' | 'full') => {
        const newProfile: UserProfile = {
            accessTier: tier, baseArchetype: null, egotend: null, highertend: null,
            ctSuppressors: null, changeThreshold: null, log: [], stateBalance: 0,
            mtraAnswers: {}, hbdiAnswers: {}, mbtiAnswers: {}
        };
        saveProfile(newProfile);
        setAssessmentStage(tier === 'full' ? 'mtra' : 'basic-taster');
    };

    const handleCompleteMTra = (results: { changeThreshold: 'High' | 'Moderate' | 'Low', ctSuppressors: string[] }, answers: Record<number, number>) => {
        if (userProfile) {
            const updatedProfile = { 
                ...userProfile, 
                ...results, 
                mtraAnswers: answers as unknown as Record<string, number> 
            };
            saveProfile(updatedProfile);
            setAssessmentData({ mtraResults: results, mtraAnswers: answers });
            setAssessmentStage('mtra-results');
        }
    };

    const handleCompleteHBDI = async (answers: { [key: number]: string }) => {
        if (userProfile) {
            const updatedProfile = { ...userProfile, hbdiAnswers: answers };
            saveProfile(updatedProfile);
        }
        setAssessmentData((prev: any) => ({ ...prev, hbdiAnswers: answers, hbdiSummary: null }));
        setAssessmentStage('hbdi-results');
        try {
            const summary = await geminiService.analyzeHbdiForSummary(answers);
            setAssessmentData((prev: any) => ({ ...prev, hbdiSummary: summary }));
        } catch (error) {
            console.error("Failed to get HBDI summary:", error);
            setAssessmentData((prev: any) => ({ ...prev, hbdiSummary: "Could not generate summary." }));
        }
    };

    const handleCompleteMBTI = async (answers: { [key: number]: string }) => {
        if (userProfile) {
            const updatedProfile = { ...userProfile, mbtiAnswers: answers };
            saveProfile(updatedProfile);
        }
        setAssessmentData((prev: any) => ({ ...prev, mbtiAnswers: answers, mbtiResults: null }));
        setAssessmentStage('mbti-results');
        try {
            const results = await geminiService.analyzeMbtiForSummary(answers);
            setAssessmentData((prev: any) => ({ ...prev, mbtiResults: results }));
        } catch (error) {
            console.error("Failed to get MBTI summary:", error);
            setAssessmentData((prev: any) => ({ ...prev, mbtiResults: { mbtiType: "Error", summary: "Could not generate summary." } }));
        }
    };

    const handleGenerateFullProfile = async () => {
        if (!userProfile || !assessmentData.mtraResults || !assessmentData.hbdiAnswers || !assessmentData.mbtiAnswers) return;
        setIsGeneratingProfile(true);

        try {
            const finalProfileParts = await geminiService.generateFullProfileFromAssessments(
                assessmentData.mtraResults,
                assessmentData.hbdiAnswers,
                assessmentData.mbtiAnswers
            );
            const finalProfile: UserProfile = {
                ...userProfile,
                baseArchetype: finalProfileParts.baseArchetype,
                egotend: finalProfileParts.egotend,
                highertend: finalProfileParts.highertend,
                ctSuppressors: assessmentData.mtraResults.ctSuppressors,
                changeThreshold: assessmentData.mtraResults.changeThreshold,
                hbdiAnswers: assessmentData.hbdiAnswers,
                mbtiAnswers: assessmentData.mbtiAnswers,
                mtraAnswers: assessmentData.mtraAnswers
            };
            saveProfile(finalProfile);
            setAssessmentStage('mios-boot');
        } catch (error) {
            console.error("Failed to generate final profile", error);
            alert("An error occurred while generating your profile. Please try again.");
            setAssessmentStage('mbti-results');
        } finally {
            setIsGeneratingProfile(false);
        }
    };


    const handleLogEvent = (logEntry: LogEntry) => {
        if (!userProfile) return;
        const newLog = [logEntry, ...userProfile.log];
        let newBalance = userProfile.stateBalance || 0;
        if (logEntry.type === 'highertend' || logEntry.type === 'egotend') {
            const balanceChange = logEntry.type === 'highertend' ? 0.1 : -0.1;
            newBalance = Math.max(-1, Math.min(1, newBalance + balanceChange));
        }
        const updatedProfile: UserProfile = { ...userProfile, log: newLog, stateBalance: newBalance };
        saveProfile(updatedProfile);
    };

    const handleImportProfile = (data: UserProfile) => {
        saveProfile(data);
        setAssessmentStage('complete');
    };

    const renderAssessment = () => {
        if (isGeneratingProfile) {
            return <FoldingSquareLoader />;
        }

        switch (assessmentStage) {
            case 'welcome':
                return <WelcomeScreen onChoice={handleWelcomeChoice} isProfileComplete={!!(userProfile && userProfile.baseArchetype)} onImportProfile={handleImportProfile} />;
            case 'tier':
                return <AccessTierSelector onSelect={handleSelectTier} />;
            case 'mtra':
                return <MTraAssessment onComplete={handleCompleteMTra} />;
            case 'mtra-results':
                return <MTraResultsScreen results={assessmentData.mtraResults} onContinue={() => setAssessmentStage('hbdi')} />;
            case 'hbdi':
                return <HBDIAssessment onComplete={handleCompleteHBDI} />;
            case 'hbdi-results':
                return <HBDIResultsScreen summary={assessmentData.hbdiSummary} onContinue={() => setAssessmentStage('mbti')} />;
            case 'mbti':
                return <MBTIAssessment onComplete={handleCompleteMBTI} />;
            case 'mbti-results':
                return <MBTIResultsScreen results={assessmentData.mbtiResults} onContinue={handleGenerateFullProfile} />;
            case 'mios-boot':
                return userProfile ? <ProfileCompleteScreen userProfile={userProfile} onEnter={() => setAssessmentStage('complete')} /> : <FoldingSquareLoader />;
            default:
                return <WelcomeScreen onChoice={handleWelcomeChoice} isProfileComplete={!!(userProfile && userProfile.baseArchetype)} onImportProfile={handleImportProfile} />;
        }
    };

    const renderTabContent = () => {
        if (!userProfile) return <FoldingSquareLoader />;
        switch(activeTab) {
            case 'mimap': return <MiMap userProfile={userProfile} onLogEvent={handleLogEvent} />;
            case 'circuit-breaker-dashboard': return <CircuitBreakerDashboard />;
            case 'misound': return <MiSound />;
            case 'tfm-audit': return <TfmAuditConsole />;
            case 'settings': return <SettingsDashboard userProfile={userProfile} onImportProfile={handleImportProfile} currentColorMode={colorMode} setColorMode={handleSetColorMode} />;
            default: return <MiMap userProfile={userProfile} onLogEvent={handleLogEvent} />;
        }
    };

    if (isLoading) {
        return <FoldingSquareLoader />;
    }

    const wrapperClassName = `theme-${colorMode}`;

    if (assessmentStage !== 'complete' || !userProfile?.baseArchetype) {
        return (
            <div className={wrapperClassName}>
                <div className="min-h-screen flex items-center justify-center p-4 bg-brand-bg relative">
                    {assessmentStage !== 'welcome' && (
                        <Button onClick={handleGoHome} className="absolute top-6 left-6 !p-2 z-10" aria-label="Go Home" variant="secondary">
                            <Home size={20} />
                        </Button>
                    )}
                    {renderAssessment()}
                </div>
            </div>
        );
    }

    const navItems = [
        { id: 'mimap', label: 'MiMap', icon: Dna },
        { id: 'circuit-breaker-dashboard', label: 'Circuit Breaker', icon: BrainCircuit },
        { id: 'misound', label: 'MiSound', icon: Volume2 },
        { id: 'tfm-audit', label: 'TFM Audit', icon: ClipboardList },
        { id: 'settings', label: 'Settings', icon: SettingsIcon },
    ];

    return (
        <div className={`min-h-screen bg-brand-bg ${wrapperClassName}`}>
            <header className="md:hidden bg-brand-surface border-b border-brand-border p-4 flex justify-between items-center fixed top-0 left-0 right-0 z-40 h-16">
                 <h1 className="text-lg font-bold text-white flex items-center gap-2"><Logo size={20} showLetters={false} /> MiType+ OS</h1>
                 <div className="flex items-center gap-2">
                    <button onClick={() => setIsNavOpen(!isNavOpen)} className="text-white">
                        {isNavOpen ? <X size={24} /> : <Menu size={24} />}
                    </button>
                 </div>
            </header>
            <div className="flex">
                <nav className={`fixed top-0 left-0 h-full w-64 bg-brand-surface p-4 border-r border-brand-border flex flex-col z-30 transform transition-transform duration-300 ease-in-out ${isNavOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 md:h-screen`}>
                    <div className="hidden md:block mb-8">
                        <h1 className="text-2xl font-bold text-white flex items-center gap-3"><Logo size={28} showLetters={false} /> MiType+ OS</h1>
                    </div>
                     <div className="md:hidden h-16" />
                    <ul className="space-y-2 flex-grow">
                        {navItems.map(item => (
                            <li key={item.id}>
                                <button
                                    onClick={() => { setActiveTab(item.id); setIsNavOpen(false); }}
                                    className={`w-full flex items-center gap-3 p-2 rounded-md text-left transition-colors ${activeTab === item.id ? 'bg-brand-primary text-white' : 'hover:bg-brand-border text-brand-text-muted'}`}
                                >
                                    <item.icon size={20} />
                                    {item.label}
                                </button>
                            </li>
                        ))}
                    </ul>
                    <div className="mt-4 pt-4 border-t border-brand-border space-y-4">
                         <button
                            onClick={handleGoHome}
                            className={`w-full flex items-center gap-3 p-2 rounded-md text-left transition-colors hover:bg-brand-border text-brand-text-muted`}
                        >
                            <Home size={20} />
                            Go Home
                        </button>
                    </div>
                </nav>
                <main className="flex-1 w-full p-4 md:p-8 pt-20 md:pt-8 overflow-y-auto">
                    <div className="max-w-7xl mx-auto">
                        {renderTabContent()}
                    </div>
                </main>
            </div>
        </div>
    );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, ChatMessage, Archetype, Egotend, Highertend } from '../types.ts';

const getAI = () => {
    const apiKey = typeof process !== 'undefined' ? process.env.API_KEY : undefined;
    if (!apiKey) {
        throw new Error("API_KEY environment variable not set. Please ensure the project has a valid Gemini API key.");
    }
    return new GoogleGenAI({ apiKey });
};

const MTypeSystemInstruction = `You are "Mi", an AI assistant integrated into the MiType+ Cognitive OS. Your purpose is to help users understand themselves through the MiType+ framework. You MUST adhere to the following rules:
1.  **Analyze Data:** When given assessment data, analyze it strictly within the MiType+ framework provided in user prompts.
2.  **Generate Profiles:** Create user profiles (Base Archetype, Egotend, Highertend) based on the analysis.
3.  **Chat Support:** When chatting, use the user's provided profile data to give contextual, supportive, and insightful advice.
4.  **Tone:** Your tone is empathetic, insightful, and slightly futuristic, like a calm OS assistant.
5.  **Output Format:** Always respond in the requested JSON format when asked. For chat, respond in clear, concise markdown.`;

export async function analyzeMTra(answers: { [key: number]: number }): Promise<any> {
    const ai = getAI();
    const prompt = `Analyze the following 20 MTra (MiType Threshold Reaction) assessment answers to determine the user's top 3 CT (Change Threshold) Suppressors and their overall Change Threshold level. The answers are on a 1-5 scale (1=Strongly Disagree, 5=Strongly Agree).

    Answers: ${JSON.stringify(answers, null, 2)}

    **Framework for Analysis:**
    - Questions 1-5: Emotional Regulation (Higher scores = higher threshold)
    - Questions 6-10: Cognitive Flexibility (Higher scores = higher threshold)
    - Questions 11-15: Stress Response (Higher scores = lower threshold)
    - Questions 16-20: Pattern Rigidity (Higher scores = lower threshold)

    An overall high score in regulation/flexibility and low score in stress/rigidity suggests a "High" Change Threshold. The opposite suggests a "Low" threshold. A mix suggests "Moderate".

    **Common Suppressors:** "Analysis Paralysis", "Conflict Aversion", "Perfectionism", "Emotional Reactivity", "Rigid Thinking", "Impatience", "Avoidance", "Catastrophizing". Identify the top 3 based on patterns in high-scoring stress/rigidity questions.

    Return a JSON object with this exact structure: { "changeThreshold": "High" | "Moderate" | "Low", "ctSuppressors": ["Suppressor 1", "Suppressor 2", "Suppressor 3"] }`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
            systemInstruction: MTypeSystemInstruction,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    changeThreshold: { type: Type.STRING },
                    ctSuppressors: { 
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                }
            },
        }
    });

    return JSON.parse(response.text);
}

export async function analyzeHbdiForSummary(answers: { [key: number]: string }): Promise<string> {
    const ai = getAI();
    const prompt = `Based on the following HBDI assessment answers, provide a brief (2-3 sentences) summary of the user's dominant cognitive preference.
    (A=Blue/Analytical, B=Green/Practical, C=Red/Relational, D=Yellow/Conceptual).
    Answers: ${JSON.stringify(answers, null, 2)}

    Example summary: "Your answers suggest a strong preference for the conceptual and relational quadrants, indicating you are an imaginative and people-oriented thinker."`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { systemInstruction: MTypeSystemInstruction }
    });

    return response.text || "Analysis complete.";
}

export async function analyzeMbtiForSummary(answers: { [key: number]: string }): Promise<{ mbtiType: string, summary: string }> {
    const ai = getAI();
    const prompt = `Analyze the following MBTI assessment answers to determine the user's 4-letter MBTI type and provide a brief (2-3 sentences) summary of this type.

    Answers: ${JSON.stringify(answers, null, 2)}

    Return a JSON object with this exact structure: { "mbtiType": "XXXX", "summary": "..." }`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
            systemInstruction: MTypeSystemInstruction,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    mbtiType: { type: Type.STRING },
                    summary: { type: Type.STRING }
                },
                required: ["mbtiType", "summary"]
            }
        }
    });

    return JSON.parse(response.text);
}


export async function generateFullProfileFromAssessments(
    mtraResults: { changeThreshold: string; ctSuppressors: string[] },
    hbdiAnswers: { [key: number]: string },
    mbtiAnswers: { [key: number]: string }
): Promise<{ baseArchetype: Archetype, egotend: Egotend, highertend: Highertend }> {
    const ai = getAI();
    const twentyFourArchetypes = [
        "Imaginative Explorer", "Transformational Leader", "Innovative Designer",
        "Creative Problem Solver", "Visionary Conceptualiser", "Passionate Advocate",
        "Dynamic Motivator", "Intuitive Strategist", "Adaptive Analyst",
        "Logical Innovator", "Holistic Integrator", "Relationship Builder",
        "Personalised Coach", "Expressive Communicator", "Methodical Producer",
        "Structured Communicator", "Empathetic Supporter", "Reliable Executor",
        "Harmonious Facilitator", "Systematic Implementer", "Strategic Planner",
        "Efficient Analyst", "Harmonious Analyst", "Detailed Organiser"
    ];

    const prompt = `Synthesize a full MiType+ profile from the user's MTra, HBDI, and MBTI assessment results.

    **1. MTra Results (Change Threshold):**
    ${JSON.stringify(mtraResults, null, 2)}

    **2. HBDI Answers (Cognitive Preference):**
    ${JSON.stringify(hbdiAnswers, null, 2)}
    (A=Blue/Analytical, B=Green/Practical, C=Red/Relational, D=Yellow/Conceptual)

    **3. MBTI Answers (Processing Style):**
    ${JSON.stringify(mbtiAnswers, null, 2)}

    **Task:**
    1. Select ONE Base Archetype from this list: ${JSON.stringify(twentyFourArchetypes)}.
    2. Define its "coreDrive".
    3. Specify "HBDI" and "MBTI" labels.
    4. Set "CTS" to ${mtraResults.changeThreshold}.
    5. Define an "Egotend" (stress state) with challenges based on suppressors: ${mtraResults.ctSuppressors.join(', ')}.
    6. Define a "Highertend" (growth state) with a "pathToGrowth".

    Return as JSON.`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
            systemInstruction: MTypeSystemInstruction,
            thinkingConfig: { thinkingBudget: 4000 },
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    baseArchetype: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            coreDrive: { type: Type.STRING },
                            HBDI: { type: Type.STRING },
                            MBTI: { type: Type.STRING },
                            CTS: { type: Type.STRING }
                        }
                    },
                    egotend: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            challenges: { type: Type.ARRAY, items: { type: Type.STRING } }
                        }
                    },
                    highertend: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            pathToGrowth: { type: Type.ARRAY, items: { type: Type.STRING } }
                        }
                    }
                }
            },
        }
    });

    return JSON.parse(response.text);
}


export async function getChatResponse(history: ChatMessage[], profile: UserProfile): Promise<string> {
    const ai = getAI();
    const userProfileContext = `This user's current MiType+ profile is:
    - Base Archetype: ${profile.baseArchetype?.name}
    - Egotend State: ${profile.egotend?.name}
    - Highertend State: ${profile.highertend?.name}
    - Current Suppressors: ${profile.ctSuppressors?.join(', ')}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: history.flatMap(h => h.parts).concat([{ text: "User context: " + userProfileContext }]) },
        config: { systemInstruction: MTypeSystemInstruction }
    });

    return response.text || "I'm listening.";
}

export async function interpretFrictionMarkers(communicationData: string, auditResults: { vagueCount: number; negativeCount: number; avoidanceCount: number; valenceScore: number; }): Promise<string> {
    const ai = getAI();
    const prompt = `Analyze communication results: Vague=${auditResults.vagueCount}, Negative=${auditResults.negativeCount}, Avoidance=${auditResults.avoidanceCount}, Valence=${auditResults.valenceScore.toFixed(2)}. Text: "${communicationData}"`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { systemInstruction: MTypeSystemInstruction }
    });

    return response.text || "No friction detected.";
}

export async function getArchetypeDetails(archetypeName: string): Promise<Pick<Archetype, 'coreDrive' | 'HBDI' | 'MBTI'>> {
    const ai = getAI();
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Details for MiType+ Archetype: "${archetypeName}". Return coreDrive, HBDI, MBTI as JSON.`,
        config: {
            systemInstruction: MTypeSystemInstruction,
            responseMimeType: "application/json"
        }
    });

    return JSON.parse(response.text);
}

